-- Add new schema named "bronze_history"
CREATE SCHEMA IF NOT EXISTS "bronze_history";
-- Create "meec_inventory_computers_history" table
CREATE TABLE "bronze_history"."meec_inventory_computers_history" (
  "history_id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "valid_from" timestamptz NOT NULL,
  "valid_to" timestamptz NULL,
  "collected_at" timestamptz NOT NULL,
  "first_collected_at" timestamptz NOT NULL,
  "resource_id" character varying NOT NULL,
  "resource_name" character varying NULL,
  "fqdn_name" character varying NULL,
  "domain_netbios_name" character varying NULL,
  "ip_address" character varying NULL,
  "mac_address" character varying NULL,
  "os_name" character varying NULL,
  "os_platform" bigint NULL,
  "os_platform_name" character varying NULL,
  "os_version" character varying NULL,
  "service_pack" character varying NULL,
  "agent_version" character varying NULL,
  "computer_live_status" bigint NULL,
  "installation_status" bigint NULL,
  "managed_status" bigint NULL,
  "branch_office_name" character varying NULL,
  "owner" character varying NULL,
  "owner_email_id" character varying NULL,
  "description" character varying NULL,
  "location" character varying NULL,
  "last_sync_time" bigint NULL,
  "agent_last_contact_time" bigint NULL,
  "agent_installed_on" bigint NULL,
  "customer_name" character varying NULL,
  "customer_id" bigint NULL,
  PRIMARY KEY ("history_id")
);
-- Create index "bronzehistorymeecinventorycomputer_collected_at" to table: "meec_inventory_computers_history"
CREATE INDEX "bronzehistorymeecinventorycomputer_collected_at" ON "bronze_history"."meec_inventory_computers_history" ("collected_at");
-- Create index "bronzehistorymeecinventorycomputer_resource_id_valid_from" to table: "meec_inventory_computers_history"
CREATE INDEX "bronzehistorymeecinventorycomputer_resource_id_valid_from" ON "bronze_history"."meec_inventory_computers_history" ("resource_id", "valid_from");
-- Create index "bronzehistorymeecinventorycomputer_valid_to" to table: "meec_inventory_computers_history"
CREATE INDEX "bronzehistorymeecinventorycomputer_valid_to" ON "bronze_history"."meec_inventory_computers_history" ("valid_to");
-- Create "meec_inventory_installed_software_history" table
